import Foundation

enum Environment: String {
    case development = "dev"
    case staging = "staging"
    case production = "prod"
}

class NetworkingManager {

    static let shared = NetworkingManager()

    private let environment: Environment

    private let baseUrl: String {
        switch environment {
        case .development:
            return "https://api.example.com.dev"
        case .staging:
            return "https://api.example.com.staging"
        case .production:
            return "https://api.example.com"
        }
    }

    private let session: URLSession

    init(environment: Environment = .production) {
        self.environment = environment
        self.session = URLSession.shared
    }

    func fetchUserData(completion: @escaping (Result<UserData, Error>) -> Void) {
        let url = URL(string: "\(baseUrl)/users")!

        let request = URLRequest(url: url)

        session.dataTask(with: request) { data, _, error in
            if let error = error {
                completion(.failure(error))
                return
            }

            guard let data = data else {
                completion(.failure(NSError(domain: "No data received", code: 0, userInfo: nil)))
                return
            }

            let decoder = JSONDecoder()
            let userData = try decoder.decode(UserData.self, from: data)
            completion(.success(userData))
        }.resume()
    }

    func authenticate(username: String, password: String, completion: @escaping (Result<String, Error>) -> Void) {
        let url = URL(string: "\(baseUrl)/auth")!

        let body = ["username": username, "password": password]

        let request = NSMutableURLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")

        let encoder = JSONEncoder()
        let data = try encoder.encode(body)

        session.dataTask(with: request as URLRequest) { data, _, error in
            if let error = error {
                completion(.failure(error))
                return
            }

            guard let data = data else {
                completion(.failure(NSError(domain: "No data received", code: 0, userInfo: nil)))
                return
            }

            let decoder = JSONDecoder()
            let token = try decoder.decode(String.self, from: data)
            completion(.success(token))
        }.resume()
    }
}

struct UserData: Codable {
    let id: Int
    let name: String
    let email: String
}